        if (dist_snuku[v] < cost) continue;



        for (int i = 0; i < G_Snuku[v].size(); i++) {

            edge e = G_Snuku[v][i];

            if (dist_snuku[e.to] > dist_snuku[v] + e.cost) {

                dist_snuku[e.to] = dist_snuku[v] + e.cost;

                Q.push(MP(dist_snuku[e.to], e.to));

            }

        }

    }

}



